package metrics

import (
	"context"
	"fmt"
)

// Sample is a single recorded metric point.
type Sample struct {
	Name  string
	Value float64
}

// Sink delivers a batch of samples to a downstream collector.
type Sink interface {
	Send(ctx context.Context, batch []Sample) error
}

// Flusher ships pending samples to a Sink in fixed-size batches.
type Flusher struct {
	sink     Sink
	maxBatch int
}

// Flush sends every sample in batches and returns the number of samples
// successfully sent. If a batch send fails it stops and returns that error so
// the caller can retry the remainder.
func (f *Flusher) Flush(ctx context.Context, samples []Sample) (int, error) {
	batches, err := split(samples, f.maxBatch)
	if err != nil {
		return 0, fmt.Errorf("split samples: %w", err)
	}

	sent := 0
	for _, batch := range batches {
		err = f.sink.Send(ctx, batch)
		if err != nil {
			break
		}
		sent += len(batch)
	}
	if err != nil {
		return sent, fmt.Errorf("flush aborted after %d samples: %w", sent, err)
	}
	return sent, nil
}

func split(samples []Sample, size int) ([][]Sample, error) {
	if size <= 0 {
		return nil, fmt.Errorf("batch size must be positive, got %d", size)
	}
	var batches [][]Sample
	for start := 0; start < len(samples); start += size {
		end := start + size
		if end > len(samples) {
			end = len(samples)
		}
		batches = append(batches, samples[start:end])
	}
	return batches, nil
}

